"use client";

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge, Icon, ScoreRing } from "@/components/shared";
import { useApp } from "@/lib/store";

export function SuperAdmin() {
  const setView = useApp((s) => s.setView);
  const providers = useApp((s) => s.providers);
  const prompts = useApp((s) => s.prompts);
  const logs = useApp((s) => s.logs);
  const flags = useApp((s) => s.flags);

  const activeProviders = providers.filter((p) => p.isActive).length;
  const activePrompts = prompts.filter((p) => p.isActive).length;
  const systemHealth = Math.round(
    (activeProviders / Math.max(1, providers.length)) * 0.4 +
    (activePrompts / Math.max(1, prompts.length)) * 0.3 +
    (flags.maintenanceMode ? 0 : 0.3)
  * 100
  );

  const quickLinks = [
    { label: "AI Providers", desc: `${activeProviders} active of ${providers.length}`, icon: "Cpu", view: "ai-providers", color: "#1154A3" },
    { label: "Prompt Library", desc: `${prompts.length} templates · ${activePrompts} active`, icon: "Brain", view: "prompts", color: "#8B5CF6" },
    { label: "Branding", desc: "Customize logo, colors, email", icon: "Palette", view: "branding", color: "#EC4899" },
    { label: "Feature Flags", desc: `${Object.values(flags).filter(Boolean).length}/${Object.keys(flags).length} enabled`, icon: "Flag", view: "feature-flags", color: "#F59E0B" },
    { label: "Audit Logs", desc: `${logs.length} recent events`, icon: "ScrollText", view: "logs", color: "#10B981" },
    { label: "Users", desc: "Manage accounts & roles", icon: "Users", view: "users", color: "#0EA5E9" },
    { label: "Analytics", desc: "Platform metrics & funnel", icon: "BarChart3", view: "analytics", color: "#1154A3" },
    { label: "Admin Overview", desc: "KPIs & usage", icon: "ShieldCheck", view: "admin", color: "#10B981" },
  ];

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-display text-2xl font-bold flex items-center gap-2"><Icon name="Crown" className="w-6 h-6 text-gold" /> Super Admin Overview</h1>
        <p className="text-sm text-muted-foreground mt-1">Full system control. Configure AI providers, branding, prompts, flags, and audit logs.</p>
      </div>

      <div className="grid lg:grid-cols-3 gap-6">
        {/* System health */}
        <Card className="gradient-brand text-white">
          <CardContent className="p-6 flex flex-col items-center justify-center text-center">
            <div className="relative">
              <ScoreRing value={Math.min(100, systemHealth)} size={120} label="Health" />
            </div>
            <div className="mt-3 font-semibold">System health</div>
            <div className="text-xs text-white/70 mt-1">
              {flags.maintenanceMode ? "Maintenance mode ON" : "All systems operational"}
            </div>
          </CardContent>
        </Card>

        {/* Stats */}
        <div className="lg:col-span-2 grid sm:grid-cols-2 gap-4">
          {[
            { label: "AI providers", value: `${activeProviders}/${providers.length}`, icon: "Cpu", color: "#1154A3" },
            { label: "Active prompts", value: `${activePrompts}/${prompts.length}`, icon: "Brain", color: "#8B5CF6" },
            { label: "Audit logs (24h)", value: logs.length, icon: "ScrollText", color: "#10B981" },
            { label: "Flags enabled", value: `${Object.values(flags).filter(Boolean).length}/${Object.keys(flags).length}`, icon: "Flag", color: "#F59E0B" },
          ].map((s) => (
            <Card key={s.label}>
              <CardContent className="p-5 flex items-center gap-3">
                <div className="w-10 h-10 rounded-lg flex items-center justify-center" style={{ background: `${s.color}15`, color: s.color }}>
                  <Icon name={s.icon} className="w-5 h-5" />
                </div>
                <div>
                  <div className="text-xl font-bold font-display">{s.value}</div>
                  <div className="text-xs text-muted-foreground">{s.label}</div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      </div>

      {/* Quick links */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg">Super admin tools</CardTitle>
          <CardDescription>Jump directly to any control panel.</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-3">
            {quickLinks.map((q) => (
              <button key={q.label} onClick={() => setView(q.view as any)} className="group text-left rounded-xl border border-border p-4 hover:shadow-premium hover:-translate-y-0.5 transition-all">
                <div className="w-10 h-10 rounded-lg flex items-center justify-center mb-3" style={{ background: `${q.color}15`, color: q.color }}>
                  <Icon name={q.icon} className="w-5 h-5" />
                </div>
                <div className="font-semibold text-sm flex items-center gap-1">
                  {q.label}
                  <Icon name="ArrowRight" className="w-3 h-3 text-muted-foreground opacity-0 group-hover:opacity-100 group-hover:translate-x-0.5 transition" />
                </div>
                <div className="text-xs text-muted-foreground mt-0.5">{q.desc}</div>
              </button>
            ))}
          </div>
        </CardContent>
      </Card>

      {/* Recent logs */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <CardTitle className="text-lg">Recent audit events</CardTitle>
            <Button size="sm" variant="outline" onClick={() => setView("logs")}>View all</Button>
          </div>
        </CardHeader>
        <CardContent>
          <div className="space-y-2 max-h-80 overflow-y-auto">
            {logs.slice(0, 10).map((l) => {
              const sevColor = l.severity === "info" ? "brand" : l.severity === "warning" ? "warning" : "danger";
              return (
                <div key={l.id} className="flex items-start gap-3 p-2 rounded-lg hover:bg-secondary/40">
                  <Badge variant={sevColor as any} className="text-[10px] capitalize shrink-0">{l.severity}</Badge>
                  <div className="flex-1 min-w-0">
                    <div className="text-sm font-medium truncate">{l.action}</div>
                    <div className="text-xs text-muted-foreground truncate">{l.details}</div>
                  </div>
                  <div className="text-xs text-muted-foreground shrink-0 whitespace-nowrap">{new Date(l.timestamp).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}</div>
                </div>
              );
            })}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

src/components/app/modules/TestConnectio:
"use client";

import { useState, useEffect } from "react";
import { motion } from "framer-motion";
import { Button } from "@/components/ui/button";
import { Badge, Icon } from "@/components/shared";
import { ProviderManager } from "@/lib/ai/services";
import type { AIProvider } from "@/lib/types";

interface TestResult {
  ok: boolean;
  latencyMs: number;
  message: string;
  response?: string;
  inputTokens?: number;
  outputTokens?: number;
}

export function TestConnectionModal({ provider, onClose }: { provider: AIProvider; onClose: () => void }) {
  const [status, setStatus] = useState<"idle" | "running" | "done">("idle");
  const [result, setResult] = useState<TestResult | null>(null);
  const [testPrompt, setTestPrompt] = useState("Reply with exactly: OK");
  const [steps, setSteps] = useState<string[]>([]);

  const runTest = async () => {
    setStatus("running");
    setSteps([]);
    setResult(null);

    setSteps((s) => [...s, `Resolving adapter for type "${provider.type}"…`]);
    await new Promise((r) => setTimeout(r, 200));
    setSteps((s) => [...s, `Building config (baseUrl=${provider.baseUrl || provider.apiUrl || "—"}, model=${provider.modelName || "—"})…`]);
    await new Promise((r) => setTimeout(r, 200));
    setSteps((s) => [...s, `Sending test prompt: "${testPrompt.slice(0, 60)}${testPrompt.length > 60 ? "…" : ""}"`]);

    const t0 = performance.now();
    const res = await ProviderManager.testConnection(provider);
    const totalMs = Math.round(performance.now() - t0);

    setSteps((s) => [...s, `Received response in ${res.latencyMs}ms (total ${totalMs}ms including overhead).`]);
    setResult(res);
    setStatus("done");
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-50 bg-background/80 backdrop-blur-sm flex items-center justify-center p-4"
      onClick={onClose}
    >
      <motion.div
        initial={{ y: 20, opacity: 0, scale: 0.97 }}
        animate={{ y: 0, opacity: 1, scale: 1 }}
        exit={{ y: 20, opacity: 0, scale: 0.97 }}
        transition={{ type: "spring", damping: 26, stiffness: 280 }}
        className="bg-card rounded-2xl border border-border shadow-premium w-full max-w-2xl max-h-[90vh] overflow-y-auto"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="sticky top-0 bg-card border-b border-border p-4 flex items-center justify-between">
          <h3 className="font-display font-bold text-lg flex items-center gap-2">
            <Icon name="Zap" className="w-5 h-5 text-gold" />
            Test Connection — {provider.name}
          </h3>
          <Button variant="ghost" size="icon" onClick={onClose}><Icon name="X" className="w-4 h-4" /></Button>
        </div>

        <div className="p-5 space-y-4">
          {/* Provider summary */}
          <div className="rounded-lg bg-secondary/50 p-3 grid grid-cols-2 sm:grid-cols-4 gap-2 text-xs">
            <div><div className="text-muted-foreground">Type</div><div className="font-medium capitalize">{provider.type.replace("-", " ")}</div></div>
            <div><div className="text-muted-foreground">Model</div><div className="font-medium font-mono truncate">{provider.modelName || "—"}</div></div>
            <div><div className="text-muted-foreground">Base URL</div><div className="font-mono truncate">{provider.baseUrl || provider.apiUrl || "—"}</div></div>
            <div><div className="text-muted-foreground">Timeout</div><div className="font-medium">{provider.timeout}ms</div></div>
          </div>

          {/* Test prompt editor */}
          <div className="space-y-1.5">
            <label className="text-xs uppercase tracking-wide text-muted-foreground">Test prompt</label>
            <input
              value={testPrompt}
              onChange={(e) => setTestPrompt(e.target.value)}
              disabled={status === "running"}
              className="w-full h-9 px-3 rounded-md border border-input bg-background text-sm disabled:opacity-50"
            />
          </div>

          {/* Run button */}
          <Button
            onClick={runTest}
            disabled={status === "running"}
            className="w-full bg-brand hover:bg-brand-dark text-white gap-2"
          >
            {status === "running" ? (
              <><Icon name="Loader2" className="w-4 h-4 animate-spin" /> Running test…</>
            ) : (
              <><Icon name="Play" className="w-4 h-4" /> Run test connection</>
            )}
          </Button>

          {/* Steps log */}
          {steps.length > 0 && (
            <div className="rounded-lg bg-slate-900 text-slate-100 p-3 font-mono text-xs space-y-1 max-h-40 overflow-y-auto">
              {steps.map((s, i) => (
                <div key={i} className="flex items-start gap-2">
                  <span className="text-emerald-400">›</span>
                  <span>{s}</span>
                </div>
              ))}
              {status === "running" && <div className="flex items-center gap-2 text-amber-300"><span className="animate-pulse">●</span> Awaiting response…</div>}
            </div>
          )}

          {/* Result */}
          {status === "done" && result && (
            <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} className="space-y-3">
              <div className={`rounded-lg p-4 ${result.ok ? "bg-emerald-100 dark:bg-emerald-400/10 border border-emerald-300" : "bg-red-100 dark:bg-red-400/10 border border-red-300"}`}>
                <div className="flex items-center gap-2">
                  <Icon name={result.ok ? "CheckCircle2" : "XCircle"} className={`w-5 h-5 ${result.ok ? "text-emerald-600" : "text-red-600"}`} />
                  <span className={`font-semibold ${result.ok ? "text-emerald-800 dark:text-emerald-300" : "text-red-800 dark:text-red-300"}`}>
                    {result.ok ? "Connection successful" : "Connection failed"}
                  </span>
                  <Badge variant={result.ok ? "success" : "danger"} className="ml-auto">{result.latencyMs}ms</Badge>
                </div>
                <div className={`mt-2 text-sm ${result.ok ? "text-emerald-700 dark:text-emerald-400" : "text-red-700 dark:text-red-400"}`}>{result.message}</div>
              </div>

              {result.response && (
                <div>
                  <div className="text-xs font-semibold uppercase text-muted-foreground mb-1">Response</div>
                  <pre className="rounded-lg border border-border bg-secondary/50 p-3 text-xs font-mono whitespace-pre-wrap max-h-40 overflow-y-auto">{result.response}</pre>
                </div>
              )}

              <div className="grid grid-cols-3 gap-2 text-xs">
                <div className="rounded-md bg-secondary p-2"><div className="text-muted-foreground">Latency</div><div className="font-mono font-semibold">{result.latencyMs}ms</div></div>
                <div className="rounded-md bg-secondary p-2"><div className="text-muted-foreground">Input tokens</div><div className="font-mono font-semibold">{result.inputTokens ?? "—"}</div></div>
                <div className="rounded-md bg-secondary p-2"><div className="text-muted-foreground">Output tokens</div><div className="font-mono font-semibold">{result.outputTokens ?? "—"}</div></div>
              </div>
            </motion.div>
          )}
        </div>

        <div className="sticky bottom-0 bg-card border-t border-border p-4 flex justify-end gap-2">
          <Button variant="outline" onClick={onClose}>Close</Button>
          {status === "done" && <Button onClick={runTest} className="bg-brand hover:bg-brand-dark text-white gap-2"><Icon name="RotateCcw" className="w-4 h-4" /> Run again</Button>}
        </div>
      </motion.div>
    </motion.div>
  );
}

src/components/app/modules/UserApprovals:
"use client";

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge, Icon } from "@/components/shared";
import { useApp } from "@/lib/store";
import { toast } from "sonner";
import { useState } from "react";

export function UserApprovals() {
  const users = useApp((s) => s.users);
  const approveUser = useApp((s) => s.approveUser);
  const deleteUser = useApp((s) => s.deleteUser);
  const [q, setQ] = useState("");

  const pending = users.filter((u) => u.status === "pending");
  const filtered = pending.filter((u) => `${u.name} ${u.email} ${u.username ?? ""}`.toLowerCase().includes(q.toLowerCase()));

  const handleApprove = (id: string, name: string) => {
    approveUser(id);
    toast.success(`${name} has been approved. They can now access all features.`);
  };

  const handleReject = (id: string, name: string) => {
    if (confirm(`Reject and delete ${name}'s account?`)) {
      deleteUser(id);
      toast.success(`${name}'s account has been deleted.`);
    }
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-display text-2xl font-bold flex items-center gap-2">
          <Icon name="UserCheck" className="w-6 h-6 text-brand" /> User Approvals
        </h1>
        <p className="text-sm text-muted-foreground mt-1">Review and approve new user registrations. Pending users cannot access any features until approved.</p>
      </div>

      <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
        <Card><CardContent className="p-4"><div className="text-2xl font-bold font-display text-amber-600">{pending.length}</div><div className="text-xs text-muted-foreground">Pending</div></CardContent></Card>
        <Card><CardContent className="p-4"><div className="text-2xl font-bold font-display text-emerald-600">{users.filter((u) => u.status === "approved").length}</div><div className="text-xs text-muted-foreground">Approved</div></CardContent></Card>
        <Card><CardContent className="p-4"><div className="text-2xl font-bold font-display text-red-600">{users.filter((u) => u.status === "suspended").length}</div><div className="text-xs text-muted-foreground">Suspended</div></CardContent></Card>
      </div>

      <Card>
        <CardHeader>
          <div className="flex items-center justify-between gap-3 flex-wrap">
            <CardTitle className="text-lg">Pending Approvals ({filtered.length})</CardTitle>
            <input value={q} onChange={(e) => setQ(e.target.value)} placeholder="Search…" className="h-9 px-3 rounded-md border border-input bg-background text-sm w-full sm:w-64" />
          </div>
        </CardHeader>
        <CardContent>
          {filtered.length === 0 ? (
            <div className="text-center py-12">
              <Icon name="CheckCircle2" className="w-10 h-10 text-emerald-500 mx-auto" />
              <p className="text-sm text-muted-foreground mt-2">No pending approvals. You're all caught up!</p>
            </div>
          ) : (
            <div className="space-y-3">
              {filtered.map((u) => (
                <div key={u.id} className="flex items-center justify-between gap-3 p-4 rounded-lg border border-border">
                  <div className="min-w-0">
                    <div className="font-semibold text-sm flex items-center gap-2">
                      {u.name}
                      <Badge variant="warning" className="text-[9px]">PENDING</Badge>
                    </div>
                    <div className="text-xs text-muted-foreground">{u.email}</div>
                    <div className="text-xs text-muted-foreground mt-0.5">
                      {u.provider} · registered {new Date(u.createdAt).toLocaleDateString()}
                    </div>
                  </div>
                  <div className="flex gap-1.5 shrink-0">
                    <Button size="sm" onClick={() => handleApprove(u.id, u.name)} className="bg-emerald-600 hover:bg-emerald-700 text-white gap-1.5">
                      <Icon name="Check" className="w-3.5 h-3.5" /> Approve
                    </Button>
                    <Button size="sm" variant="outline" onClick={() => handleReject(u.id, u.name)} className="text-destructive gap-1.5">
                      <Icon name="X" className="w-3.5 h-3.5" /> Reject
                    </Button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

src/components/app/modules/UserDetailMod:
"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { Badge, Icon } from "@/components/shared";
import { useApp } from "@/lib/store";
import { toast } from "sonner";
import type { Role } from "@/lib/types";

export interface ManagedUser {
  id: string;
  name: string;
  email: string;
  role: Role;
  status: "active" | "suspended";
  resumes: number;
  lastActive: string;
  provider: string;
  createdAt: string;
  avatarColor: string;
}

export function UserDetailModal({ user, onClose }: { user: ManagedUser; onClose: () => void }) {
  const currentUser = useApp((s) => s.user);
  const log = useApp((s) => s.log);

  const [name, setName] = useState(user.name);
  const [email, setEmail] = useState(user.email);
  const [role, setRole] = useState<Role>(user.role);
  const [status, setStatus] = useState<"active" | "suspended">(user.status);
  const [saving, setSaving] = useState(false);

  const isSelf = currentUser?.email === user.email;
  const canEditRole = currentUser?.role === "super_admin" && !isSelf;
  const canSuspend = currentUser?.role === "super_admin" && !isSelf;

  const save = async () => {
    setSaving(true);
    await new Promise((r) => setTimeout(r, 400));
    setSaving(false);
    log({
      actor: currentUser?.email ?? "admin",
      action: "User updated",
      category: "admin",
      details: `${user.email}: name="${name}", role=${role}, status=${status}`,
      severity: "info",
    });
    toast.success(`Changes saved for ${user.name}.`);
    onClose();
  };

  const resetPassword = () => {
    if (!confirm(`Send a password-reset email to ${user.email}?`)) return;
    log({
      actor: currentUser?.email ?? "admin",
      action: "Password reset triggered",
      category: "auth",
      details: `Reset email sent to ${user.email}`,
      severity: "warning",
    });
    toast.success(`Password-reset email sent to ${user.email}.`);
  };

  const initials = user.name.split(/\s+/).slice(0, 2).map((s) => s[0]?.toUpperCase()).join("");

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-50 bg-background/80 backdrop-blur-sm flex items-center justify-center p-0 sm:p-4"
      onClick={onClose}
    >
      <motion.div
        initial={{ y: 20, opacity: 0, scale: 0.97 }}
        animate={{ y: 0, opacity: 1, scale: 1 }}
        exit={{ y: 20, opacity: 0, scale: 0.97 }}
        transition={{ type: "spring", damping: 26, stiffness: 280 }}
        className="bg-card rounded-t-2xl sm:rounded-2xl border border-border shadow-premium w-full sm:max-w-xl max-h-[95vh] overflow-y-auto"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="sticky top-0 bg-card border-b border-border p-4 flex items-center justify-between">
          <h3 className="font-display font-bold text-lg flex items-center gap-2">
            <Icon name="User" className="w-5 h-5 text-brand" /> User details
          </h3>
          <Button variant="ghost" size="icon" onClick={onClose}><Icon name="X" className="w-4 h-4" /></Button>
        </div>

        <div className="p-5 space-y-5">
          {/* Avatar + identity */}
          <div className="flex items-center gap-4">
            <div className="w-16 h-16 rounded-full flex items-center justify-center text-white font-bold text-xl shrink-0" style={{ background: user.avatarColor }}>
              {initials || "?"}
            </div>
            <div className="min-w-0">
              <div className="font-semibold text-lg flex items-center gap-2">
                {user.name}
                {isSelf && <Badge variant="brand" className="text-[10px]">YOU</Badge>}
              </div>
              <div className="text-sm text-muted-foreground truncate">{user.email}</div>
              <div className="flex flex-wrap gap-1.5 mt-1">
                <Badge variant={user.role === "super_admin" ? "gold" : user.role === "admin" ? "brand" : "outline"} className="capitalize text-[10px]">{user.role.replace("_", " ")}</Badge>
                <Badge variant={user.status === "active" ? "success" : "danger"} className="capitalize text-[10px]">{user.status}</Badge>
                <Badge variant="outline" className="capitalize text-[10px]">{user.provider}</Badge>
              </div>
            </div>
          </div>

          {/* Stats */}
          <div className="grid grid-cols-3 gap-2">
            <div className="rounded-lg bg-secondary p-3 text-center">
              <div className="text-xl font-bold font-display">{user.resumes}</div>
              <div className="text-xs text-muted-foreground">Resumes</div>
            </div>
            <div className="rounded-lg bg-secondary p-3 text-center">
              <div className="text-xl font-bold font-display">{user.lastActive}</div>
              <div className="text-xs text-muted-foreground">Last active</div>
            </div>
            <div className="rounded-lg bg-secondary p-3 text-center">
              <div className="text-xl font-bold font-display">{new Date(user.createdAt).getFullYear()}</div>
              <div className="text-xs text-muted-foreground">Joined</div>
            </div>
          </div>

          {/* Editable fields */}
          <div className="grid sm:grid-cols-2 gap-3">
            <div className="space-y-1.5">
              <Label className="text-xs uppercase tracking-wide text-muted-foreground">Display name</Label>
              <Input value={name} onChange={(e) => setName(e.target.value)} disabled={isSelf ? false : !canEditRole} />
            </div>
            <div className="space-y-1.5">
              <Label className="text-xs uppercase tracking-wide text-muted-foreground">Email</Label>
              <Input value={email} onChange={(e) => setEmail(e.target.value)} disabled />
              <p className="text-[11px] text-muted-foreground flex items-center gap-1"><Icon name="Lock" className="w-3 h-3" /> Email changes require user verification.</p>
            </div>
            <div className="space-y-1.5">
              <Label className="text-xs uppercase tracking-wide text-muted-foreground">Role</Label>
              <select
                value={role}
                onChange={(e) => setRole(e.target.value as Role)}
                disabled={!canEditRole}
                className="w-full h-9 px-3 rounded-md border border-input bg-background text-sm disabled:opacity-50"
              >
                <option value="user">User</option>
                <option value="admin">Admin</option>
                <option value="super_admin">Super Admin</option>
              </select>
              {!canEditRole && <p className="text-[11px] text-muted-foreground">{isSelf ? "You can't change your own role." : "Only Super Admins can change roles."}</p>}
            </div>
            <div className="space-y-1.5">
              <Label className="text-xs uppercase tracking-wide text-muted-foreground">Account status</Label>
              <div className="flex items-center justify-between gap-3 p-2 rounded-md border border-input h-9">
                <span className="text-sm">{status === "active" ? "Active" : "Suspended"}</span>
                <Switch checked={status === "active"} onCheckedChange={(v) => setStatus(v ? "active" : "suspended")} disabled={!canSuspend} />
              </div>
              {!canSuspend && <p className="text-[11px] text-muted-foreground">{isSelf ? "You can't suspend your own account." : "Only Super Admins can suspend users."}</p>}
            </div>
          </div>

          {/* Actions */}
          <div className="rounded-lg border border-border p-3 space-y-2">
            <div className="text-sm font-medium">Account actions</div>
            <div className="flex flex-wrap gap-2">
              <Button size="sm" variant="outline" onClick={resetPassword} className="gap-1.5">
                <Icon name="Mail" className="w-3.5 h-3.5" /> Send password reset
              </Button>
              <Button
                size="sm"
                variant="outline"
                onClick={() => {
                  log({ actor: currentUser?.email ?? "admin", action: "User data exported", category: "admin", details: user.email, severity: "info" });
                  toast.success(`Data export queued for ${user.email}.`);
                }}
                className="gap-1.5"
              >
                <Icon name="Download" className="w-3.5 h-3.5" /> Export user data
              </Button>
              {canSuspend && status === "active" ? (
                <Button size="sm" variant="outline" className="text-destructive gap-1.5" onClick={() => { setStatus("suspended"); toast.info("Mark as suspended, then Save to apply."); }}>
                  <Icon name="UserX" className="w-3.5 h-3.5" /> Suspend
                </Button>
              ) : canSuspend && status === "suspended" ? (
                <Button size="sm" variant="outline" className="text-emerald-600 gap-1.5" onClick={() => { setStatus("active"); toast.info("Mark as active, then Save to apply."); }}>
                  <Icon name="UserCheck" className="w-3.5 h-3.5" /> Reactivate
                </Button>
              ) : null}
            </div>
          </div>
        </div>

        <div className="sticky bottom-0 bg-card border-t border-border p-4 flex justify-end gap-2">
          <Button variant="outline" onClick={onClose}>Cancel</Button>
          <Button onClick={save} disabled={saving} className="bg-brand hover:bg-brand-dark text-white gap-2">
            {saving ? <Icon name="Loader2" className="w-4 h-4 animate-spin" /> : <Icon name="Save" className="w-4 h-4" />}
            Save changes
          </Button>
        </div>
      </motion.div>
    </motion.div>
  );
}

src/components/app/modules/Users.tsx:
"use client";

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge, Icon } from "@/components/shared";
import { useApp } from "@/lib/store";
import { toast } from "sonner";
import { UserDetailModal, type ManagedUser } from "./UserDetailModal";
import { validatePassword } from "@/lib/auth-utils";

const AVATAR_COLORS = ["#1154A3", "#F59E0B", "#10B981", "#8B5CF6", "#EC4899", "#0EA5E9", "#DC2626", "#0B1F3A"];

export function Users() {
  const users = useApp((s) => s.users);
  const currentUser = useApp((s) => s.user);
  const approveUser = useApp((s) => s.approveUser);
  const suspendUser = useApp((s) => s.suspendUser);
  const unsuspendUser = useApp((s) => s.unsuspendUser);
  const deleteUser = useApp((s) => s.deleteUser);
  const promoteToAdmin = useApp((s) => s.promoteToAdmin);
  const demoteToUser = useApp((s) => s.demoteToUser);
  const resetUserPassword = useApp((s) => s.resetUserPassword);
  const log = useApp((s) => s.log);

  const [q, setQ] = useState("");
  const [roleFilter, setRoleFilter] = useState("all");
  const [statusFilter, setStatusFilter] = useState("all");
  const [selected, setSelected] = useState<ManagedUser | null>(null);
  const [resetTarget, setResetTarget] = useState<ManagedUser | null>(null);
  const [newPassword, setNewPassword] = useState("");

  const filtered = users.filter((u) => {
    if (roleFilter !== "all" && u.role !== roleFilter) return false;
    if (statusFilter !== "all" && u.status !== statusFilter) return false;
    if (q && !`${u.name} ${u.email} ${u.username ?? ""}`.toLowerCase().includes(q.toLowerCase())) return false;
    return true;
  });

  const stats = {
    total: users.length,
    approved: users.filter((u) => u.status === "approved").length,
    pending: users.filter((u) => u.status === "pending").length,
    suspended: users.filter((u) => u.status === "suspended").length,
    deleted: users.filter((u) => u.status === "deleted").length,
  };

  const toManaged = (u: any): ManagedUser => ({
    id: u.id,
    name: u.name,
    email: u.email,
    role: u.role,
    status: u.status === "suspended" ? "suspended" : "active",
    resumes: u.usage?.resumesGenerated ?? 0,
    lastActive: u.lastActiveAt ? new Date(u.lastActiveAt).toLocaleDateString() : "Never",
    provider: u.provider || "email",
    createdAt: u.createdAt,
    avatarColor: AVATAR_COLORS[users.indexOf(u) % AVATAR_COLORS.length],
  });

  const handleAction = (action: string, user: any) => {
    const isSelf = user.email === currentUser?.email;
    if (isSelf && action !== "view") {
      toast.error("You cannot perform this action on your own account.");
      return;
    }
    switch (action) {
      case "approve": approveUser(user.id); toast.success(`${user.name} approved.`); break;
      case "suspend": suspendUser(user.id); toast.success(`${user.name} suspended.`); break;
      case "unsuspend": unsuspendUser(user.id); toast.success(`${user.name} reactivated.`); break;
      case "delete": if (confirm(`Delete ${user.name}? (soft delete — data preserved)`)) { deleteUser(user.id); toast.success(`${user.name} deleted.`); } break;
      case "promote": promoteToAdmin(user.id); toast.success(`${user.name} promoted to admin.`); break;
      case "demote": demoteToUser(user.id); toast.success(`${user.name} demoted to user.`); break;
      case "reset": setResetTarget(toManaged(user)); setNewPassword(""); break;
    }
  };

  const handleResetPassword = () => {
    if (!resetTarget) return;
    const check = validatePassword(newPassword);
    if (!check.valid) {
      toast.error(`Password requirements: ${check.errors.join(", ")}`);
      return;
    }
    // Find the user by email
    const targetUser = users.find((u) => u.id === resetTarget.id);
    if (targetUser) {
      resetUserPassword(targetUser.id, newPassword);
      toast.success(`Password reset for ${resetTarget.name}.`);
    }
    setResetTarget(null);
    setNewPassword("");
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h1 className="font-display text-2xl font-bold flex items-center gap-2"><Icon name="Users" className="w-6 h-6 text-brand" /> User Management</h1>
          <p className="text-sm text-muted-foreground mt-1">Manage users, roles, and status. Approve, suspend, promote, or delete accounts.</p>
        </div>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-5 gap-4">
        {[
          { label: "Total", value: stats.total, icon: "Users", color: "#1154A3" },
          { label: "Approved", value: stats.approved, icon: "CheckCircle2", color: "#10B981" },
          { label: "Pending", value: stats.pending, icon: "Clock", color: "#F59E0B" },
          { label: "Suspended", value: stats.suspended, icon: "Ban", color: "#DC2626" },
          { label: "Deleted", value: stats.deleted, icon: "Trash2", color: "#6B7280" },
        ].map((s) => (
          <Card key={s.label}>
            <CardContent className="p-4 flex items-center gap-3">
              <div className="w-9 h-9 rounded-lg flex items-center justify-center" style={{ background: `${s.color}15`, color: s.color }}>
                <Icon name={s.icon} className="w-4 h-4" />
              </div>
              <div><div className="text-lg font-bold font-display">{s.value}</div><div className="text-xs text-muted-foreground">{s.label}</div></div>
            </CardContent>
          </Card>
        ))}
      </div>

      <Card>
        <CardHeader>
          <div className="flex items-center justify-between gap-3 flex-wrap">
            <CardTitle className="text-lg">All Users ({filtered.length})</CardTitle>
            <div className="flex flex-wrap gap-2">
              <select value={roleFilter} onChange={(e) => setRoleFilter(e.target.value)} className="h-9 px-3 rounded-md border border-input bg-background text-sm">
                <option value="all">All roles</option>
                <option value="user">User</option>
                <option value="admin">Admin</option>
                <option value="super_admin">Super Admin</option>
              </select>
              <select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)} className="h-9 px-3 rounded-md border border-input bg-background text-sm">
                <option value="all">All statuses</option>
                <option value="approved">Approved</option>
                <option value="pending">Pending</option>
                <option value="suspended">Suspended</option>
                <option value="deleted">Deleted</option>
              </select>
              <div className="relative w-full sm:w-64">
                <Icon name="Search" className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <Input value={q} onChange={(e) => setQ(e.target.value)} placeholder="Search…" className="pl-9 h-9" />
              </div>
            </div>
          </div>
        </CardHeader>
        <CardContent className="p-0">
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead className="border-b border-border bg-secondary/50">
                <tr className="text-left text-xs uppercase tracking-wide text-muted-foreground">
                  <th className="px-4 py-2 font-semibold">User</th>
                  <th className="px-4 py-2 font-semibold">Role</th>
                  <th className="px-4 py-2 font-semibold">Provider</th>
                  <th className="px-4 py-2 font-semibold">Status</th>
                  <th className="px-4 py-2 font-semibold">Registered</th>
                  <th className="px-4 py-2 font-semibold">Last Login</th>
                  <th className="px-4 py-2 font-semibold text-right">Actions</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map((u, idx) => {
                  const isSelf = u.email === currentUser?.email;
                  const canManage = currentUser?.role === "super_admin" && !isSelf;
                  return (
                    <tr key={u.id} className="border-b border-border hover:bg-secondary/30">
                      <td className="px-4 py-3">
                        <div className="flex items-center gap-2">
                          <div className="w-8 h-8 rounded-full flex items-center justify-center text-white text-xs font-semibold shrink-0" style={{ background: AVATAR_COLORS[idx % AVATAR_COLORS.length] }}>
                            {u.name.split(/\s+/).slice(0, 2).map((s) => s[0]?.toUpperCase()).join("")}
                          </div>
                          <div className="min-w-0">
                            <div className="font-medium flex items-center gap-1.5">{u.name}{isSelf && <Badge variant="brand" className="text-[9px]">YOU</Badge>}</div>
                            <div className="text-xs text-muted-foreground truncate">{u.email}</div>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 py-3"><Badge variant={u.role === "super_admin" ? "gold" : u.role === "admin" ? "brand" : "outline"} className="capitalize text-[10px]">{u.role.replace("_", " ")}</Badge></td>
                      <td className="px-4 py-3 text-xs capitalize text-muted-foreground">{u.provider}</td>
                      <td className="px-4 py-3"><Badge variant={u.status === "approved" ? "success" : u.status === "pending" ? "warning" : u.status === "suspended" ? "danger" : "outline"} className="capitalize text-[10px]">{u.status}</Badge></td>
                      <td className="px-4 py-3 text-xs text-muted-foreground">{new Date(u.createdAt).toLocaleDateString()}</td>
                      <td className="px-4 py-3 text-xs text-muted-foreground">{u.lastLoginAt ? new Date(u.lastLoginAt).toLocaleDateString() : "Never"}</td>
                      <td className="px-4 py-3">
                        <div className="flex gap-0.5 justify-end flex-wrap">
                          {u.status === "pending" && <IconBtn icon="Check" label="Approve" color="#10B981" onClick={() => handleAction("approve", u)} disabled={!canManage} />}
                          {u.status === "approved" && <IconBtn icon="Ban" label="Suspend" color="#DC2626" onClick={() => handleAction("suspend", u)} disabled={!canManage} />}
                          {u.status === "suspended" && <IconBtn icon="UserCheck" label="Unsuspend" color="#10B981" onClick={() => handleAction("unsuspend", u)} disabled={!canManage} />}
                          {u.role === "user" && <IconBtn icon="ArrowUp" label="Promote to admin" color="#1154A3" onClick={() => handleAction("promote", u)} disabled={!canManage} />}
                          {u.role === "admin" && <IconBtn icon="ArrowDown" label="Demote to user" color="#64748B" onClick={() => handleAction("demote", u)} disabled={!canManage} />}
                          <IconBtn icon="KeyRound" label="Reset password" color="#F59E0B" onClick={() => handleAction("reset", u)} disabled={!canManage} />
                          <IconBtn icon="Eye" label="View details" onClick={() => setSelected(toManaged(u))} />
                          {u.status !== "deleted" && <IconBtn icon="Trash2" label="Delete" color="#DC2626" onClick={() => handleAction("delete", u)} disabled={!canManage} />}
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </CardContent>
      </Card>

      {selected && <UserDetailModal user={selected} onClose={() => setSelected(null)} />}
      {resetTarget && (
        <div className="fixed inset-0 z-50 bg-background/80 backdrop-blur-sm flex items-center justify-center p-4" onClick={() => setResetTarget(null)}>
          <div className="bg-card rounded-2xl border border-border shadow-premium w-full max-w-md p-6 space-y-4" onClick={(e) => e.stopPropagation()}>
            <h3 className="font-display font-bold text-lg flex items-center gap-2"><Icon name="KeyRound" className="w-5 h-5 text-brand" /> Reset Password</h3>
            <p className="text-sm text-muted-foreground">Set a new password for <strong>{resetTarget.name}</strong> ({resetTarget.email})</p>
            <Input type="password" value={newPassword} onChange={(e) => setNewPassword(e.target.value)} placeholder="Min 12 chars, Aa1!" />
            {newPassword && <p className="text-xs text-muted-foreground">Password must have 12+ chars, uppercase, lowercase, number, special char</p>}
            <div className="flex gap-2 justify-end">
              <Button variant="outline" onClick={() => setResetTarget(null)}>Cancel</Button>
              <Button onClick={handleResetPassword} className="bg-brand hover:bg-brand-dark text-white">Reset password</Button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function IconBtn({ icon, label, onClick, color, disabled }: { icon: string; label: string; onClick: () => void; color?: string; disabled?: boolean }) {
  return (
    <button onClick={onClick} title={label} aria-label={label} disabled={disabled} className="w-7 h-7 rounded-md hover:bg-secondary flex items-center justify-center text-muted-foreground hover:text-foreground transition disabled:opacity-30 disabled:cursor-not-allowed" style={color ? { color } : undefined}>
      <Icon name={icon} className="w-3.5 h-3.5" />
    </button>
  );
}

