              {resume.headline && <div style={{ fontSize: "10.5pt", color: BLACK, marginBottom: "0.5mm", lineHeight: 1.2 }}>{resume.headline}</div>}
              <div style={{ fontSize: "10.5pt", color: BLACK, marginBottom: "0.3mm", lineHeight: 1.2 }}>
