  const doc = new Document({ sections: [{ properties: { page: { margin: { top: convertInchesToTwip(0.8), bottom: convertInchesToTwip(0.8), left: convertInchesToTwip(0.9), right: convertInchesToTwip(0.9) } } }, children }] });
  const blob = await Packer.toBlob(doc);
  saveAs(blob, (cl.title || "cover_letter").replace(/\s+/g, "_") + ".docx");
}

// ---------- Interview package ----------

export function exportInterviewPDF(pkg: InterviewPackage) {
  const doc = new jsPDF({ unit: "mm", format: "a4", orientation: "portrait" });
  const { w: pageW, h: pageH } = A4;
  const left = MARGIN;
  const right = pageW - MARGIN;
  const contentW = right - left;
  let y = MARGIN;

  // Header band
  doc.setFillColor(17, 84, 163);
  doc.rect(0, 0, pageW, 18, "F");
  doc.setFont("helvetica", "bold");
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(16);
  doc.text("Interview Preparation Package", left, y + 8);
  y += 24;

  doc.setTextColor(100, 116, 139);
  doc.setFont("helvetica", "normal");
  doc.setFontSize(10);
  doc.text(`${pkg.role || "Role"}${pkg.company ? " at " + pkg.company : ""}`, left, y);
  y += 8;

  const grouped: Record<string, typeof pkg.questions> = {};
  for (const q of pkg.questions) (grouped[q.category] ||= []).push(q);

  const categoryLabels: Record<string, string> = {
    technical: "Technical Questions",
    behavioral: "Behavioral Questions",
    situational: "Situational Questions",
    hr: "HR Questions",
    company: "Company-Specific Questions",
  };

  for (const cat of ["technical", "behavioral", "situational", "hr", "company"]) {
    if (!grouped[cat]) continue;
    if (y > pageH - MARGIN - 20) { doc.addPage(); y = MARGIN; }
    doc.setFont("helvetica", "bold");
    doc.setTextColor(17, 84, 163);
    doc.setFontSize(12);
    doc.text(categoryLabels[cat], left, y);
    y += 6;
    doc.setDrawColor(17, 84, 163);
    doc.line(left, y, right, y);
    y += 6;

    for (const q of grouped[cat]) {
      if (y > pageH - MARGIN - 40) { doc.addPage(); y = MARGIN; }
      doc.setFont("helvetica", "bold");
      doc.setTextColor(11, 31, 58);
      doc.setFontSize(10.5);
      y = drawWrappedText(doc, `Q${pkg.questions.indexOf(q) + 1}. ${q.question}`, left, y, contentW, 10.5, 3);
      y += 1;

      doc.setFont("helvetica", "italic");
      doc.setTextColor(245, 158, 11);
      doc.setFontSize(9);
      doc.text(`Difficulty: ${q.difficulty.toUpperCase()}`, left, y);
      y += 5;

      doc.setFont("helvetica", "bold");
      doc.setTextColor(11, 31, 58);
      doc.setFontSize(10);
      doc.text("Recommended answer:", left, y);
      y += 5;
      doc.setFont("helvetica", "normal");
      doc.setTextColor(33, 49, 70);
      y = drawWrappedText(doc, q.recommendedAnswer, left + 2, y, contentW - 2, 10, 3);
      y += 2;

      if (q.talkingPoints?.length) {
        doc.setFont("helvetica", "bold");
        doc.setTextColor(11, 31, 58);
        doc.setFontSize(10);
        doc.text("Talking points:", left, y);
        y += 4;
        for (const t of q.talkingPoints) {
          if (y > pageH - MARGIN - 12) { doc.addPage(); y = MARGIN; }
          y = drawBullet(doc, t, left, y, contentW, 9.5, 2);
        }
        y += 1;
      }

      if (q.starExample) {
        doc.setFont("helvetica", "bold");
        doc.setTextColor(11, 31, 58);
        doc.setFontSize(10);
        doc.text("STAR example:", left, y);
        y += 4;
        doc.setFont("helvetica", "normal");
        doc.setTextColor(33, 49, 70);
        y = drawWrappedText(doc, `Situation: ${q.starExample.situation}`, left + 2, y, contentW - 2, 9.5, 2);
        y = drawWrappedText(doc, `Task: ${q.starExample.task}`, left + 2, y, contentW - 2, 9.5, 2);
        y = drawWrappedText(doc, `Action: ${q.starExample.action}`, left + 2, y, contentW - 2, 9.5, 2);
        y = drawWrappedText(doc, `Result: ${q.starExample.result}`, left + 2, y, contentW - 2, 9.5, 2);
        y += 2;
      }

      if (q.followUps?.length) {
        doc.setFont("helvetica", "bold");
        doc.setTextColor(11, 31, 58);
        doc.setFontSize(10);
        doc.text("Follow-up questions:", left, y);
        y += 4;
        for (const f of q.followUps) {
          if (y > pageH - MARGIN - 10) { doc.addPage(); y = MARGIN; }
          y = drawBullet(doc, f, left, y, contentW, 9.5, 2);
        }
        y += 2;
      }
      y += 4;
    }
  }

  doc.save((`interview_prep_${(pkg.company || "package").replace(/\s+/g, "_")}`).toLowerCase() + ".pdf");
}

export async function exportInterviewDOCX(pkg: InterviewPackage) {
  const children: Paragraph[] = [];
  children.push(new Paragraph({ children: [new TextRun({ text: "Interview Preparation Package", bold: true, size: 36, color: "1154A3" })], spacing: { after: 80 } }));
  children.push(new Paragraph({ children: [new TextRun({ text: `${pkg.role || "Role"}${pkg.company ? " at " + pkg.company : ""}`, size: 22, color: "64748B", italics: true })], spacing: { after: 200 } }));

  const grouped: Record<string, typeof pkg.questions> = {};
  for (const q of pkg.questions) (grouped[q.category] ||= []).push(q);
  const labels: Record<string, string> = { technical: "Technical Questions", behavioral: "Behavioral Questions", situational: "Situational Questions", hr: "HR Questions", company: "Company-Specific Questions" };

  for (const cat of ["technical", "behavioral", "situational", "hr", "company"]) {
    if (!grouped[cat]) continue;
    children.push(sectionPara(labels[cat], "1154A3"));
    for (const q of grouped[cat]) {
      children.push(new Paragraph({ children: [new TextRun({ text: `Q. ${q.question}`, bold: true, size: 22, color: "0B1F3A" })], spacing: { after: 40 } }));
      children.push(new Paragraph({ children: [new TextRun({ text: `Difficulty: ${q.difficulty.toUpperCase()}`, italics: true, size: 18, color: "F59E0B" })], spacing: { after: 60 } }));
      children.push(new Paragraph({ children: [new TextRun({ text: "Recommended answer:", bold: true, size: 20 })], spacing: { after: 30 } }));
      children.push(new Paragraph({ children: [new TextRun({ text: q.recommendedAnswer, size: 20, color: "1F2937" })], spacing: { after: 100 } }));
      if (q.talkingPoints?.length) {
        children.push(new Paragraph({ children: [new TextRun({ text: "Talking points:", bold: true, size: 20 })], spacing: { after: 30 } }));
        for (const t of q.talkingPoints) children.push(new Paragraph({ bullet: { level: 0 }, children: [new TextRun({ text: t, size: 20 })], spacing: { after: 20 } }));
      }
      if (q.starExample) {
        children.push(new Paragraph({ children: [new TextRun({ text: "STAR example:", bold: true, size: 20 })], spacing: { after: 30 } }));
        children.push(new Paragraph({ children: [new TextRun({ text: `Situation: ${q.starExample.situation}`, size: 20 })], spacing: { after: 20 } }));
        children.push(new Paragraph({ children: [new TextRun({ text: `Task: ${q.starExample.task}`, size: 20 })], spacing: { after: 20 } }));
        children.push(new Paragraph({ children: [new TextRun({ text: `Action: ${q.starExample.action}`, size: 20 })], spacing: { after: 20 } }));
        children.push(new Paragraph({ children: [new TextRun({ text: `Result: ${q.starExample.result}`, size: 20 })], spacing: { after: 80 } }));
      }
      if (q.followUps?.length) {
        children.push(new Paragraph({ children: [new TextRun({ text: "Follow-up questions:", bold: true, size: 20 })], spacing: { after: 30 } }));
        for (const f of q.followUps) children.push(new Paragraph({ bullet: { level: 0 }, children: [new TextRun({ text: f, size: 20 })], spacing: { after: 20 } }));
      }
      children.push(new Paragraph({ spacing: { after: 200 }, children: [] }));
    }
  }

  const doc = new Document({ sections: [{ properties: { page: { margin: { top: convertInchesToTwip(0.7), bottom: convertInchesToTwip(0.7), left: convertInchesToTwip(0.8), right: convertInchesToTwip(0.8) } } }, children }] });
  const blob = await Packer.toBlob(doc);
  saveAs(blob, (`interview_prep_${(pkg.company || "package").replace(/\s+/g, "_")}`).toLowerCase() + ".docx");
}

src/lib/job-intelligence.ts:
// ResumeAI Pro — Job Intelligence Engine
// Analyzes a job description and extracts structured intelligence:
//   - Required skills (technical + soft)
//   - Required experience (years, roles)
//   - Required languages
//   - Required competencies
//   - Preferred qualifications
//   - Industry / business function
//   - Recruiter intent
//
// This engine runs BEFORE optimization so the optimizer can prioritize
// job requirements over original-resume keywords.

"use client";

import { callAI, extractJSON } from "./ai";
import type { JobDescription } from "./types";

export interface JobIntelligence {
  // Core required skills (the MUST-HAVES)
  requiredSkills: string[];
  // Preferred skills (nice-to-haves)
  preferredSkills: string[];
  // Required experience (years + role types)
  requiredExperienceYears: number;
  requiredRoles: string[];
  // Required languages
  requiredLanguages: string[];
  // Required competencies (behavioral)
  requiredCompetencies: string[];
  // Required technical skills
  requiredTechnicalSkills: string[];
  // Required soft skills
  requiredSoftSkills: string[];
  // Required industry knowledge
  requiredIndustryKnowledge: string[];
  // Preferred qualifications
  preferredQualifications: string[];
  // Industry / business function
  industry: string;
  businessFunction: string;
  // Recruiter intent (what the recruiter is actually looking for)
  recruiterIntent: string;
  // Role title (normalized)
  roleTitle: string;
  // Company
  company: string;
  // Top 10 priority keywords (ranked by importance — these are what the
  // optimizer MUST embed naturally, in order of priority)
  priorityKeywords: string[];
  // Keywords to AVOID (irrelevant to this job — e.g. "airport security" for a
  // call center role)
  avoidKeywords: string[];
}

/**
 * Analyze a job description and extract structured intelligence.
 * Uses the configured AI provider (via callAI).
 */
export async function analyzeJobIntelligence(jd: JobDescription): Promise<JobIntelligence> {
  const jdText = jd.rawText || [
    `Title: ${jd.title}`,
    jd.company ? `Company: ${jd.company}` : "",
    jd.location ? `Location: ${jd.location}` : "",
    jd.responsibilities?.length ? `Responsibilities:\n${jd.responsibilities.map((r) => `  - ${r}`).join("\n")}` : "",
    jd.requiredSkills?.length ? `Required Skills:\n${jd.requiredSkills.map((s) => `  - ${s}`).join("\n")}` : "",
    jd.preferredSkills?.length ? `Preferred Skills:\n${jd.preferredSkills.map((s) => `  - ${s}`).join("\n")}` : "",
    jd.keywords?.length ? `Keywords: ${jd.keywords.join(", ")}` : "",
  ].filter(Boolean).join("\n\n");

  const prompt = `You are a Job Intelligence Analyst. Analyze this job description and extract structured intelligence.

JOB DESCRIPTION:
${jdText}

Extract:
1. Required skills (MUST-HAVES — the candidate MUST have these)
2. Preferred skills (nice-to-haves)
3. Required experience (years + role types)
4. Required languages
5. Required competencies (behavioral — e.g. "customer service", "problem solving")
6. Required technical skills (e.g. "CRM", "Excel", "POS systems")
7. Required soft skills (e.g. "communication", "active listening")
8. Required industry knowledge (e.g. "aviation", "retail", "hospitality")
9. Preferred qualifications
10. Industry + business function (e.g. "aviation / customer service")
11. Recruiter intent — what is the recruiter ACTUALLY looking for? (1-2 sentences)
12. Top 10 PRIORITY keywords — ranked by importance. These are the keywords the resume optimizer MUST embed naturally, in priority order.
13. Keywords to AVOID — keywords that are IRRELEVANT to this job and should NOT be emphasized (e.g. "airport security" for a call center role).

Return ONLY valid JSON:
{
  "requiredSkills": ["skill1", "skill2", ...],
  "preferredSkills": ["skill1", ...],
  "requiredExperienceYears": 2,
  "requiredRoles": ["Customer Service Agent", "Call Center Representative", ...],
  "requiredLanguages": ["English", "French", ...],
  "requiredCompetencies": ["customer service", "problem solving", ...],
  "requiredTechnicalSkills": ["CRM", "POS", ...],
  "requiredSoftSkills": ["communication", "active listening", ...],
  "requiredIndustryKnowledge": ["aviation", "retail", ...],
  "preferredQualifications": ["Bachelor's degree", ...],
  "industry": "aviation",
  "businessFunction": "customer service",
  "recruiterIntent": "Looking for a customer-focused agent who can handle high-volume call center operations...",
  "roleTitle": "Customer Contact Centre Agent",
  "company": "${jd.company || ""}",
  "priorityKeywords": ["customer service", "call handling", "communication", ...],
  "avoidKeywords": ["airport security", "passenger profiling", ...]
}`;

  try {
    const result = await callAI({
      systemPrompt: "You are a Job Intelligence Analyst. You extract structured intelligence from job descriptions. Always return ONLY valid JSON — no prose, no markdown fences.",
      userPrompt: prompt,
      maxTokens: 3000,
      temperature: 0.3,
    });

    const data = extractJSON<JobIntelligence>(result.text);
    return normalizeJobIntelligence(data, jd);
  } catch (e: any) {
    console.warn("[JobIntelligence] Analysis failed, using fallback:", e?.message);
    return fallbackJobIntelligence(jd);
  }
}

function normalizeJobIntelligence(data: any, jd: JobDescription): JobIntelligence {
  return {
    requiredSkills: Array.isArray(data.requiredSkills) ? data.requiredSkills : (jd.requiredSkills || []),
    preferredSkills: Array.isArray(data.preferredSkills) ? data.preferredSkills : (jd.preferredSkills || []),
    requiredExperienceYears: typeof data.requiredExperienceYears === "number" ? data.requiredExperienceYears : 0,
    requiredRoles: Array.isArray(data.requiredRoles) ? data.requiredRoles : [],
    requiredLanguages: Array.isArray(data.requiredLanguages) ? data.requiredLanguages : [],
    requiredCompetencies: Array.isArray(data.requiredCompetencies) ? data.requiredCompetencies : [],
    requiredTechnicalSkills: Array.isArray(data.requiredTechnicalSkills) ? data.requiredTechnicalSkills : [],
    requiredSoftSkills: Array.isArray(data.requiredSoftSkills) ? data.requiredSoftSkills : [],
    requiredIndustryKnowledge: Array.isArray(data.requiredIndustryKnowledge) ? data.requiredIndustryKnowledge : [],
    preferredQualifications: Array.isArray(data.preferredQualifications) ? data.preferredQualifications : [],
    industry: data.industry || "",
    businessFunction: data.businessFunction || "",
    recruiterIntent: data.recruiterIntent || "",
    roleTitle: data.roleTitle || jd.title || "",
    company: data.company || jd.company || "",
    priorityKeywords: Array.isArray(data.priorityKeywords) ? data.priorityKeywords.slice(0, 10) : (jd.keywords || []).slice(0, 10),
    avoidKeywords: Array.isArray(data.avoidKeywords) ? data.avoidKeywords : [],
  };
}

function fallbackJobIntelligence(jd: JobDescription): JobIntelligence {
  return {
    requiredSkills: jd.requiredSkills || [],
    preferredSkills: jd.preferredSkills || [],
    requiredExperienceYears: 0,
    requiredRoles: [],
    requiredLanguages: [],
    requiredCompetencies: [],
    requiredTechnicalSkills: [],
    requiredSoftSkills: [],
    requiredIndustryKnowledge: [],
    preferredQualifications: [],
    industry: "",
    businessFunction: "",
    recruiterIntent: "",
    roleTitle: jd.title || "",
    company: jd.company || "",
    priorityKeywords: (jd.keywords || []).slice(0, 10),
    avoidKeywords: [],
  };
}

src/lib/output-validator.ts:
// ResumeAI Pro — Output Validation Pipeline
// Runs multiple validators on a generated resume BEFORE PDF generation.
// Only generates PDF if ALL validators pass.
//
// Validators:
//   1. Layout Validation — section order, fonts, spacing
//   2. Content Validation — no forbidden sections, no error leaks
//   3. Grammar Validation — basic grammar checks
//   4. ATS Validation — ATS-friendly formatting
//   5. Job Relevance Validation — relevance score >= 90
//   6. AI Leak Validation — no AI error messages
//   7. Page Validation — fits on one A4 page

"use client";

import type { ResumeData, JobDescription } from "./types";
import { validateResumeContent, isForbiddenSection } from "./ai-error-filter";
import { computeRelevanceScore } from "./relevance-engine";
import type { JobIntelligence } from "./job-intelligence";

export interface ValidationCheck {
  name: string;
  passed: boolean;
  score?: number;
  details: string;
  errors?: string[];
}

export interface PipelineResult {
  allPassed: boolean;
  checks: ValidationCheck[];
  relevanceScore?: number;
  blockReason?: string;
}

/**
 * Run the full validation pipeline on a resume.
 * Returns allPassed=true only if every check passes.
 */
export function runValidationPipeline(
  resume: ResumeData,
  jd: JobDescription | null,
  ji: JobIntelligence | null,
): PipelineResult {
  const checks: ValidationCheck[] = [];

  // === 1. LAYOUT VALIDATION ===
  checks.push(validateLayout(resume));

  // === 2. CONTENT VALIDATION ===
  checks.push(validateContent(resume));

  // === 3. GRAMMAR VALIDATION ===
  checks.push(validateGrammar(resume));

  // === 4. ATS VALIDATION ===
  checks.push(validateATS(resume));

  // === 5. JOB RELEVANCE VALIDATION ===
  let relevanceScore: number | undefined;
  if (ji) {
    const relCheck = validateJobRelevance(resume, ji);
    checks.push(relCheck);
    relevanceScore = relCheck.score;
  }

  // === 6. AI LEAK VALIDATION ===
  checks.push(validateNoAILeaks(resume));

  // === 7. PAGE VALIDATION (heuristic — actual page count checked at PDF render) ===
  checks.push(validatePageFit(resume));

  const allPassed = checks.every((c) => c.passed);
  const failedCheck = checks.find((c) => !c.passed);

  return {
    allPassed,
    checks,
    relevanceScore,
    blockReason: failedCheck ? `${failedCheck.name}: ${failedCheck.details}` : undefined,
  };
}

// ============================================================================
// INDIVIDUAL VALIDATORS
// ============================================================================

function validateLayout(resume: ResumeData): ValidationCheck {
  const errors: string[] = [];

  // Check section order: Summary → Skills → Experience → Education → Languages
  // We verify that the resume has the required sections (not necessarily in order,
  // since the renderer enforces order — but we check that the data exists)
  if (!resume.summary || resume.summary.length < 30) {
    errors.push("Missing or too-short professional summary");
  }
  if (!resume.skills || resume.skills.length === 0) {
    errors.push("Missing skills section");
  }
  if (!resume.experience || resume.experience.length === 0) {
    errors.push("Missing professional experience section");
  }
  if (!resume.education || resume.education.length === 0) {
    errors.push("Missing education section");
  }
  if (!resume.languages || resume.languages.length === 0) {
    errors.push("Missing languages section");
  }

  // Check template is infohas-pro (the reference template)
  if (resume.template !== "infohas-pro") {
    errors.push(`Wrong template: expected "infohas-pro", got "${resume.template}"`);
  }

  return {
    name: "Layout Validation",
    passed: errors.length === 0,
    details: errors.length === 0 ? "All required sections present, template correct" : `${errors.length} layout issue(s)`,
    errors,
  };
}

function validateContent(resume: ResumeData): ValidationCheck {
  const result = validateResumeContent(resume);
  return {
    name: "Content Validation",
    passed: result.valid,
    details: result.valid
      ? "No forbidden content or error leaks detected"
      : `${result.errors.length} content issue(s) detected`,
    errors: result.errors,
  };
}

function validateGrammar(resume: ResumeData): ValidationCheck {
  const errors: string[] = [];

  // Basic grammar checks
  // 1. Check for ALL CAPS words (excluding acronyms)
  const allText = [resume.summary, resume.headline, resume.name]
    .concat(resume.experience.flatMap((e) => [e.title, e.company, ...e.bullets]))
    .filter(Boolean)
    .join(" ");

  const capsWords = allText.match(/\b[A-Z]{4,}\b/g) || [];
  // Allow common acronyms
  const allowedAcronyms = ["HTML", "CSS", "API", "SQL", "AWS", "CRM", "POS", "HR", "IT", "CEO", "CFO", "CTO", "KPI", "SLA", "B2B", "B2C", "SOP", "STEB", "FAB"];
  const badCaps = capsWords.filter((w) => !allowedAcronyms.includes(w));
  if (badCaps.length > 3) {
    errors.push(`Excessive ALL CAPS words detected (${badCaps.length})`);
  }

  // 2. Check for excessively long sentences (> 250 chars)
  const sentences = allText.split(/[.!?]+/).filter((s) => s.trim().length > 0);
  const longSentences = sentences.filter((s) => s.length > 250);
  if (longSentences.length > 0) {
    errors.push(`${longSentences.length} overly long sentence(s) detected`);
  }

  // 3. Check for repeated words ("the the", "and and")
  const repeated = allText.match(/\b(\w+)\s+\1\b/gi);
  if (repeated && repeated.length > 0) {
    errors.push(`${repeated.length} repeated word(s) detected`);
  }

  return {
    name: "Grammar Validation",
    passed: errors.length === 0,
    details: errors.length === 0 ? "Grammar checks passed" : `${errors.length} grammar issue(s)`,
    errors,
  };
}

function validateATS(resume: ResumeData): ValidationCheck {
  const errors: string[] = [];

  // ATS-friendly checks:
  // 1. No special characters in name
  if (resume.name && /[<>{}[\]|\\\/]/.test(resume.name)) {
    errors.push("Special characters in name (not ATS-friendly)");
  }

  // 2. Contact info present
  if (!resume.contact?.email && !resume.contact?.phone) {
    errors.push("Missing contact information (email or phone)");
  }

  // 3. No tables/columns (can't check from data, but check for pipe characters)
  const allText = JSON.stringify(resume);
  if ((allText.match(/\|/g) || []).length > 5) {
    errors.push("Pipe characters detected (possible table formatting — not ATS-friendly)");
  }

  // 4. Experience entries have dates
  for (const e of resume.experience) {
    if (!e.startDate && !e.endDate) {
      errors.push(`Experience entry "${e.title}" missing dates`);
    }
  }

  // 5. Skills are present and not empty
  if (resume.skills.some((s) => !s.name || s.name.length < 2)) {
    errors.push("Some skills have empty or too-short names");
  }

  return {
    name: "ATS Validation",
    passed: errors.length === 0,
    details: errors.length === 0 ? "ATS-friendly formatting" : `${errors.length} ATS issue(s)`,
    errors,
  };
}

function validateJobRelevance(resume: ResumeData, ji: JobIntelligence): ValidationCheck {
  const score = computeRelevanceScore(resume, ji);
  return {
    name: "Job Relevance Validation",
    passed: score.passes,
    score: score.overall,
    details: score.passes
      ? `Relevance score: ${score.overall}/100 (>= 90 threshold)`
      : `Relevance score: ${score.overall}/100 (< 90 threshold — regenerate). Missing keywords: ${score.details.missingPriorityKeywords.slice(0, 5).join(", ")}`,
    errors: score.passes ? undefined : [`Missing ${score.details.missingPriorityKeywords.length} priority keywords`, `${score.details.avoidKeywordsFound.length} irrelevant keywords found`],
  };
}

function validateNoAILeaks(resume: ResumeData): ValidationCheck {
  // This is a more thorough check than validateContent — specifically for AI error messages
  const result = validateResumeContent(resume);
  const aiErrors = result.errors.filter((e) => e.includes("AI error leak"));

  return {
    name: "AI Leak Validation",
    passed: aiErrors.length === 0,
    details: aiErrors.length === 0
      ? "No AI error messages or system messages detected"
      : `${aiErrors.length} AI leak(s) detected — MUST NOT appear in final resume`,
    errors: aiErrors,
  };
}

function validatePageFit(resume: ResumeData): ValidationCheck {
  // Heuristic: estimate if the content will fit on one A4 page
  // A4 page with 10.5pt font and compact spacing fits roughly:
  //   - Summary: ~6 lines
  //   - Skills: ~4 lines
  //   - Experience: ~3 entries × 5 lines = 15 lines
  //   - Education: ~2 lines
  //   - Languages: ~2 lines
  // Total: ~29 lines max

  let estimatedLines = 0;

  // Summary: ~1 line per 12 words
  if (resume.summary) {
    estimatedLines += Math.ceil(resume.summary.split(/\s+/).length / 12);
  }

  // Skills: 1 line per group (assume 4 groups)
  estimatedLines += Math.min(4, Math.ceil(resume.skills.length / 3));

  // Experience: 1 header line + 1 line per bullet per entry
  for (const e of resume.experience) {
    estimatedLines += 1 + e.bullets.length;
  }

  // Education: 1 line per entry
  estimatedLines += resume.education.length;

  // Languages: 1 line per entry
  estimatedLines += resume.languages.length;

  const MAX_LINES = 35; // conservative estimate for one A4 page
  const fits = estimatedLines <= MAX_LINES;

  return {
    name: "Page Validation",
    passed: fits,
    details: fits
      ? `Estimated ${estimatedLines} lines (fits one A4 page)`
      : `Estimated ${estimatedLines} lines (exceeds ${MAX_LINES}-line max — compress content)`,
    errors: fits ? undefined : ["Content too long for one page — compress summary, reduce bullets, or merge skills"],
  };
}

