src/lib/types.ts:
// ResumeAI Pro — core domain types

export type Role = "guest" | "user" | "admin" | "super_admin";

export type UserStatus = "pending" | "approved" | "suspended" | "deleted";

export interface User {
  id: string;
  name: string;
  username?: string;
  email: string;
  passwordHash?: string;
  avatarUrl?: string;
  role: Role;
  status: UserStatus;
  provider: "email" | "puter";
  createdAt: string;
  updatedAt?: string;
  lastActiveAt: string;
  lastLoginAt?: string;
  usage: {
    resumesGenerated: number;
    atsChecks: number;
    coverLetters: number;
    interviewPreps: number;
    downloads: number;
  };
}

export interface ContactInfo {
