  },
  // Images: disable optimization (Cloudflare Pages doesn't support the default loader)
  images: {
    unoptimized: true,
  },
  // Note: Next.js 16 removed the top-level `api` config key.
  // `externalResolver` was only needed for custom servers and is no longer
